<script>
import { mapState } from "vuex";
import GMap from "../../Tables/map/Map.vue";
export default {
  components: {
    // Detail
    GMap
  },
  data() {
    return {
      // show: false,
      drop: false,
      loading: false,
      search: "",
      selectedIndex: 0,
      tabdata: [],
      selectedName: "",
      opened: [],
      searchNames: [],
      displayValue: "none",
      headers: [
        { text: "" },
        { text: "Date", value: "date" },
        { text: "Location", value: "location" },
        { text: "facility", value: "facility" },
        { text: "Mobile No.", value: "pid" },
        { text: "Name", value: "name" },
        { text: "Bill", value: "bill" }
      ]
      // details:[
      //     {date: '24/07/2019',vid:'12586725', facility:'Nyaho Medical Center', location:'Spanner',pid:'561161', name:'Jude', bill:'$545'},
      //     {date: '24/07/2019',vid:'12552687', facility:'Nyaho Medical Center', location:'Spanner',pid:'561161', name:'Peter', bill:'$767'},
      //     {date: '24/07/2019',vid:'89875520', facility:'Nyaho Medical Center', location:'Spanner',pid:'561161', name:'Paul', bill:'$234'},
      //     {date: '24/07/2019',vid:'78978925', facility:'Nyaho Medical Center', location:'Spanner',pid:'561161', name:'Silas', bill:'$424'},
      //     {date: '24/07/2019',vid:'12598909', facility:'Nyaho Medical Center', location:'Spanner',pid:'561161', name:'John', bill:'$786'},
      //     {date: '24/07/2019',vid:'68079878', facility:'Nyaho Medical Center', location:'Spanner',pid:'561161', name:'Thomas', bill:'$1232'},
      //     {date: '24/07/2019',vid:'79079358', facility:'Nyaho Medical Center', location:'Spanner',pid:'561161', name:'Judas', bill:'$547'},
      //     {date: '24/07/2019',vid:'45454565', facility:'Nyaho Medical Center', location:'Spanner',pid:'561161', name:'John', bill:'$7445'},
      // ]
    };
  },
  methods: {
    removeComplaint() {
      this.search = "";
    },

    toggle(i) {
      this.drop = !this.drop;
      this.selectedIndex = i;
      const index = this.opened.indexOf(i);
      if (index > -1) {
        this.opened.splice(index, 1);
      } else {
        this.opened.push(i);
      }
    },

    nameSearch(i) {
      this.search = this.tableData[i].name;
    }
  },
  computed: {
    ...mapState({
      sz_companyid: state => state.corporate.company_id
    }),

    tableData() {
      return this.tabdata
        .map(el => ({
          name: el["patientname"],
          date: el["created_on"],
          bill: el["charge"],
          facility: el["providername"],
          location: el["providerlocation"],
          pid: el["patientid"]
        }))
        .filter(el => {
          let search = this.search.toLowerCase();
          if (
            el.name
              .toString()
              .toLowerCase()
              .search(search) > -1 ||
            el.facility
              .toString()
              .toLowerCase()
              .search(search) > -1
          )
            return true;
          else return false;
        });
    }
  },
  created() {
    this.$Progress.start();
    this.loading = true;
    this.$store
      .dispatch("fetchActivities", this.sz_companyid)
      .then(res => {
        const params_arr = [];
        res.data.results.forEach(el => {
          params_arr.push(el);
        });
        this.tabdata = [...params_arr];
        this.loading = false;
        this.$snotify.info(
          `${res.data.results.length} employee activities were found`
        );
      })
      .catch(e => {
        console.log(e);
        this.loading = false;
        this.$snotify.error(
          "Could not get the list of your employee activities"
        );
      });
  }
};
</script>

